INSERT INTO `apipreconditions` VALUES (1, 1, NULL, '网络连通性检查', 'environment', '{\"timeout\": 5000, \"target_url\": \"https://www.baidu.com\", \"check_network\": true}', '确保测试环境能够正常访问百度服务器', 1, 1001, 1001, '2025-09-23 22:39:41', '2025-09-23 22:39:41', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (2, 1, NULL, '服务可用性检查', 'environment', '{\"check_url\": \"https://www.baidu.com\", \"retry_times\": 3, \"expected_status\": 200}', '检查百度搜索服务是否处于可用状态', 1, 1001, 1002, '2025-09-23 22:39:48', '2025-09-23 22:39:48', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (3, 2, NULL, 'AK密钥配置验证', 'auth', '{\"key_name\": \"ak\", \"location\": \"query\", \"auth_type\": \"api_key\", \"validation_rule\": \"not_empty\"}', '验证百度地图AK密钥是否正确配置', 1, 1002, 1002, '2025-09-23 22:39:54', '2025-09-23 22:39:54', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (4, 2, NULL, '每日配额检查', 'setup', '{\"check_quota\": true, \"daily_limit\": 10000, \"current_usage\": 3500}', '检查百度地图API的每日调用配额是否充足', 0, 1002, 1003, '2025-09-23 22:40:01', '2025-09-23 22:40:01', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (5, 3, NULL, '签名生成验证', 'auth', '{\"params\": [\"q\", \"from\", \"to\", \"appid\", \"salt\", \"secret\"], \"algorithm\": \"MD5\", \"auth_type\": \"signature\", \"secret_key\": \"your_secret\"}', '验证百度翻译API的签名生成逻辑', 1, 1003, 1003, '2025-09-23 22:40:09', '2025-09-23 22:40:09', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (6, 3, NULL, '语言支持检查', 'data', '{\"default_to\": \"zh\", \"default_from\": \"auto\", \"supported_languages\": [\"zh\", \"en\", \"jp\", \"kor\"]}', '检查翻译接口支持的语言类型', 0, 1003, 1001, '2025-09-23 22:40:16', '2025-09-23 22:40:16', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1001, 2001, 3001, '用户身份认证令牌获取', 'auth', '{\"body\": {\"password\": \"${env.PASSWORD}\", \"username\": \"${env.USERNAME}\"}, \"path\": \"/api/v1/auth/token\", \"method\": \"POST\", \"extract\": {\"token\": \"$.data.accessToken\"}, \"headers\": {\"Content-Type\": \"application/json\"}}', '获取访问接口所需的Bearer Token', 1, 5001, NULL, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1002, 2002, 3002, '测试数据初始化', 'setup', '{\"body\": {\"dataType\": \"user_profile\", \"projectId\": 10001}, \"path\": \"/api/v1/test-data/setup\", \"method\": \"POST\", \"headers\": {\"Authorization\": \"Bearer ${token}\"}}', '创建测试所需的用户基础数据', 1, 5002, 5001, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1003, 2003, 3003, '订单查询数据准备', 'data', '{\"body\": {\"quantity\": 2, \"productId\": \"P10025\"}, \"path\": \"/api/v1/orders\", \"method\": \"POST\", \"extract\": {\"orderId\": \"$.data.orderNo\"}, \"headers\": {\"Authorization\": \"Bearer ${token}\"}}', '创建测试订单用于后续查询操作', 1, 5003, NULL, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1004, 2004, 3004, '环境变量配置检查', 'environment', '{\"timeout\": 5000, \"checklist\": [\"DATABASE_URL\", \"CACHE_HOST\", \"MQ_ENDPOINT\"]}', '验证测试环境的基础服务可用性', 1, 5001, 5002, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1005, 2005, 3005, '支付权限验证', 'auth', '{\"path\": \"/api/v1/auth/verify\", \"expect\": {\"body\": {\"$.hasPaymentPermission\": true}, \"status\": 200}, \"method\": \"GET\", \"headers\": {\"Authorization\": \"Bearer ${token}\"}}', '验证用户是否具有支付操作权限', 1, 5004, NULL, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1006, 2006, 3006, '库存数据预热', 'data', '{\"body\": {\"skuCode\": \"SKU2024001\", \"quantity\": 1000}, \"path\": \"/api/v1/inventory/stock\", \"method\": \"PUT\", \"headers\": {\"Authorization\": \"Bearer ${token}\"}}', '预先设置测试商品的库存数量', 0, 5002, 5003, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1007, 2007, 3007, '用户会话初始化', 'setup', '{\"body\": {\"userId\": 100001, \"deviceId\": \"DEV202406001\"}, \"path\": \"/api/v1/session/init\", \"method\": \"POST\", \"headers\": {\"Authorization\": \"Bearer ${token}\"}}', '初始化用户会话状态', 1, 5003, NULL, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1008, 2008, 3008, '地理位置服务认证', 'auth', '{\"path\": \"/api/v1/location/auth\", \"method\": \"POST\", \"extract\": {\"locationToken\": \"$.auth.token\"}, \"headers\": {\"X-API-Key\": \"${env.LOCATION_API_KEY}\"}}', '获取地理位置服务访问令牌', 1, 5001, 5004, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
INSERT INTO `apipreconditions` VALUES (1009, 2009, 3009, '测试用户注册', 'setup', '{\"body\": {\"email\": \"test_${timestamp}@example.com\", \"password\": \"Test@123456\", \"username\": \"testuser_${timestamp}\"}, \"path\": \"/api/v1/users/register\", \"method\": \"POST\", \"extract\": {\"userId\": \"$.data.userId\"}}', '注册临时测试用户账号', 1, 5005, NULL, '2025-09-19 17:52:20', '2025-09-19 17:52:20', 0, NULL, NULL);
