-- ----------------------------
-- Table structure for apiversions
-- ----------------------------
DROP TABLE IF EXISTS `apiversions`;
CREATE TABLE `apiversions`  (
  `version_id` int NOT NULL AUTO_INCREMENT COMMENT '版本ID，自增主键',
  `api_id` int NOT NULL COMMENT '接口ID，关联Apis表',
  `version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '版本号，遵循语义化版本规范',
  `version_type` enum('major','minor','patch') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'minor' COMMENT '版本类型',
  `request_schema` json NULL COMMENT '请求Schema定义，JSON Schema格式',
  `request_parameters` json NULL COMMENT '请求参数定义',
  `request_headers` json NULL COMMENT '请求头定义',
  `request_body_type` enum('json','form-data','x-www-form-urlencoded','xml','raw','binary') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '请求体类型',
  `request_body_example` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '请求体示例',
  `response_schema` json NULL COMMENT '响应Schema定义，JSON Schema格式',
  `response_headers` json NULL COMMENT '响应头定义',
  `response_body_type` enum('json','xml','html','text') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '响应体类型',
  `response_examples` json NULL COMMENT '响应示例，包含成功、失败等多种情况',
  `change_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '变更描述',
  `change_type` enum('added','modified','deprecated','removed') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'modified' COMMENT '变更类型',
  `breaking_change` tinyint(1) NULL DEFAULT 0 COMMENT '是否破坏性变更',
  `status` enum('draft','active','deprecated','archived') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'draft' COMMENT '版本状态',
  `is_current` tinyint(1) NULL DEFAULT 0 COMMENT '是否为当前最新版本',
  `created_by` int NOT NULL COMMENT '创建人ID，关联Users表',
  `reviewed_by` int NULL DEFAULT NULL COMMENT '审核人ID',
  `approved_by` int NULL DEFAULT NULL COMMENT '批准人ID',
  `deprecated_by` int NULL DEFAULT NULL COMMENT '弃用人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deprecated_at` timestamp NULL DEFAULT NULL COMMENT '弃用时间',
  PRIMARY KEY (`version_id`) USING BTREE,
  UNIQUE INDEX `uk_api_version`(`api_id` ASC, `version` ASC) USING BTREE,
  INDEX `idx_api_id`(`api_id` ASC) USING BTREE,
  INDEX `idx_version`(`version` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_is_current`(`is_current` ASC) USING BTREE,
  INDEX `idx_created_by`(`created_by` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '接口版本历史表，管理接口的版本变更历史' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of apiversions
-- ----------------------------

-- ----------------------------
-- Table structure for departments
-- ----------------------------
DROP TABLE IF EXISTS `departments`;
CREATE TABLE `departments`  (
  `department_id` int NOT NULL AUTO_INCREMENT COMMENT '部门ID，自增主键',
  `department_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '部门编码，唯一标识',
  `department_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '部门名称',
  `parent_id` int NULL DEFAULT NULL COMMENT '父部门ID，关联本表主键',
  `manager_id` int NULL DEFAULT NULL COMMENT '部门负责人ID，关联Users表',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '部门描述',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序顺序',
  `level` int NULL DEFAULT 1 COMMENT '部门层级（1为最高级）',
  `path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '部门路径（存储所有上级部门ID）',
  `is_leaf` tinyint(1) NULL DEFAULT 1 COMMENT '是否为叶子部门（无子部门）',
  `status` enum('active','inactive','archived') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'active' COMMENT '部门状态',
  `established_date` date NULL DEFAULT NULL COMMENT '成立日期',
  `created_by` int NOT NULL COMMENT '创建人ID，关联Users表',
  `updated_by` int NULL DEFAULT NULL COMMENT '更新人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`department_id`) USING BTREE,
  UNIQUE INDEX `uk_department_code`(`department_code` ASC) USING BTREE,
  INDEX `idx_parent_id`(`parent_id` ASC) USING BTREE,
  INDEX `idx_department_code`(`department_code` ASC) USING BTREE,
  INDEX `idx_manager_id`(`manager_id` ASC) USING BTREE,
  INDEX `idx_level`(`level` ASC) USING BTREE,
  INDEX `idx_path`(`path`(255) ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '部门信息表' ROW_FORMAT = Dynamic;

