-- ----------------------------
-- Table structure for httprequestresponses
-- ----------------------------
DROP TABLE IF EXISTS `httprequestresponses`;
CREATE TABLE `httprequestresponses`  (
  `http_id` bigint NOT NULL AUTO_INCREMENT,
  `result_id` bigint NOT NULL COMMENT '关联TestCaseResults',
  `step_id` bigint NULL DEFAULT NULL COMMENT '关联TestStepResults',
  `http_method` enum('GET','POST','PUT','DELETE','PATCH','HEAD','OPTIONS') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `request_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `request_headers` json NULL COMMENT '请求头',
  `request_body` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '请求体',
  `request_body_type` enum('JSON','FORM_DATA','XML','RAW','BINARY') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '请求体类型',
  `response_status_code` int NULL DEFAULT NULL COMMENT '响应状态码',
  `response_status_text` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '响应状态文本',
  `response_headers` json NULL COMMENT '响应头',
  `response_body` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '响应体',
  `response_body_type` enum('JSON','XML','HTML','TEXT','BINARY') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '响应体类型',
  `response_size` bigint NULL DEFAULT 0 COMMENT '响应大小(字节)',
  `response_time` bigint NULL DEFAULT 0 COMMENT '响应时间(毫秒)',
  `request_time` datetime NULL DEFAULT NULL COMMENT '请求时间',
  `response_time_dt` datetime NULL DEFAULT NULL COMMENT '响应时间',
  `dns_time` bigint NULL DEFAULT 0 COMMENT 'DNS查询时间',
  `connect_time` bigint NULL DEFAULT 0 COMMENT '连接时间',
  `ssl_time` bigint NULL DEFAULT 0 COMMENT 'SSL握手时间',
  `ttfb_time` bigint NULL DEFAULT 0 COMMENT '首字节时间',
  `download_time` bigint NULL DEFAULT 0 COMMENT '下载时间',
  `error_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '错误类型',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '错误信息',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`http_id`) USING BTREE,
  INDEX `idx_result_id`(`result_id` ASC) USING BTREE,
  INDEX `idx_step_id`(`step_id` ASC) USING BTREE,
  INDEX `idx_http_method`(`http_method` ASC) USING BTREE,
  INDEX `idx_status_code`(`response_status_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'HTTP请求响应详情表' ROW_FORMAT = Dynamic;

