-- ----------------------------
-- Table structure for projectenvironments
-- ----------------------------
DROP TABLE IF EXISTS `projectenvironments`;
CREATE TABLE `projectenvironments`  (
  `project_env_id` int NOT NULL AUTO_INCREMENT COMMENT '项目环境关联ID，自增主键',
  `project_id` int NOT NULL COMMENT '项目ID，关联Projects表',
  `env_id` int NOT NULL COMMENT '环境ID，关联EnvironmentConfigs表',
  `environment_config` json NULL COMMENT '项目在该环境的特定配置',
  `variables_override` json NULL COMMENT '环境变量覆盖',
  `status` enum('active','inactive','maintenance') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'active' COMMENT '关联状态',
  `is_default_environment` tinyint(1) NULL DEFAULT 0 COMMENT '是否为项目默认环境',
  `deployment_config` json NULL COMMENT '部署配置',
  `last_deployed_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '最后部署版本',
  `last_deployed_at` timestamp NULL DEFAULT NULL COMMENT '最后部署时间',
  `deployment_status` enum('success','failed','in_progress','not_deployed') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'not_deployed' COMMENT '部署状态',
  `test_config` json NULL COMMENT '测试配置',
  `notification_config` json NULL COMMENT '通知配置',
  `resource_quota` json NULL COMMENT '资源配额',
  `created_by` int NOT NULL COMMENT '创建人ID，关联Users表',
  `updated_by` int NULL DEFAULT NULL COMMENT '更新人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`project_env_id`) USING BTREE,
  UNIQUE INDEX `uk_project_env`(`project_id` ASC, `env_id` ASC) USING BTREE,
  INDEX `idx_project_id`(`project_id` ASC) USING BTREE,
  INDEX `idx_env_id`(`env_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_is_default`(`is_default_environment` ASC) USING BTREE,
  INDEX `idx_deployment_status`(`deployment_status` ASC) USING BTREE,
  INDEX `idx_created_by`(`created_by` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '项目环境关联表，管理项目在不同环境的配置和状态' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of projectenvironments
-- ----------------------------

-- ----------------------------
-- Table structure for projectmembers
-- ----------------------------
DROP TABLE IF EXISTS `projectmembers`;
CREATE TABLE `projectmembers`  (
  `member_id` int NOT NULL AUTO_INCREMENT COMMENT '成员关系ID，自增主键',
  `project_id` int NOT NULL COMMENT '项目ID，关联Projects表',
  `user_id` int NOT NULL COMMENT '用户ID，关联Users表',
  `permission_level` enum('read','write','admin') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'read' COMMENT '权限级别：只读、可编辑、管理员',
  `project_role` enum('owner','manager','developer','tester','viewer') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'viewer' COMMENT '项目角色',
  `status` enum('active','inactive','removed') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'active' COMMENT '成员状态',
  `join_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '加入时间',
  `leave_time` timestamp NULL DEFAULT NULL COMMENT '离开时间',
  `last_active_time` timestamp NULL DEFAULT NULL COMMENT '最后活跃时间',
  `assigned_tasks` int NULL DEFAULT 0 COMMENT '分配任务数',
  `completed_tasks` int NULL DEFAULT 0 COMMENT '完成任务数',
  `additional_roles` json NULL COMMENT '附加角色信息',
  `custom_permissions` json NULL COMMENT '自定义权限配置',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '备注信息',
  `created_by` int NOT NULL COMMENT '添加人ID，关联Users表',
  `updated_by` int NULL DEFAULT NULL COMMENT '最后更新人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`member_id`) USING BTREE,
  UNIQUE INDEX `uk_project_user`(`project_id` ASC, `user_id` ASC) USING BTREE,
  INDEX `idx_project_id`(`project_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_permission_level`(`permission_level` ASC) USING BTREE,
  INDEX `idx_project_role`(`project_role` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_join_time`(`join_time` ASC) USING BTREE,
  INDEX `idx_leave_time`(`leave_time` ASC) USING BTREE,
  INDEX `idx_created_by`(`created_by` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 55 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '项目成员关联表，管理项目成员权限和角色' ROW_FORMAT = Dynamic;

