-- ----------------------------
-- Table structure for testexecutiontimelines
-- ----------------------------
DROP TABLE IF EXISTS `testexecutiontimelines`;
CREATE TABLE `testexecutiontimelines`  (
  `timeline_id` bigint NOT NULL AUTO_INCREMENT,
  `report_id` bigint NOT NULL,
  `event_type` enum('SUITE_START','SUITE_END','TEST_START','TEST_END','STEP_START','STEP_END','ASSERTION','ERROR','LOG') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `event_time` datetime NOT NULL,
  `event_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `event_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `suite_id` int NULL DEFAULT NULL,
  `case_id` int NULL DEFAULT NULL,
  `result_id` bigint NULL DEFAULT NULL,
  `step_id` bigint NULL DEFAULT NULL,
  `event_data` json NULL COMMENT '事件数据',
  `duration` bigint NULL DEFAULT 0 COMMENT '事件耗时',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`timeline_id`) USING BTREE,
  INDEX `idx_report_id`(`report_id` ASC) USING BTREE,
  INDEX `idx_event_time`(`event_time` ASC) USING BTREE,
  INDEX `idx_event_type`(`event_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '测试执行时间线表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of testexecutiontimelines
-- ----------------------------

-- ----------------------------
-- Table structure for testhistorytrends
-- ----------------------------
DROP TABLE IF EXISTS `testhistorytrends`;
CREATE TABLE `testhistorytrends`  (
  `trend_id` bigint NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `trend_date` date NOT NULL COMMENT '趋势日期',
  `trend_type` enum('DAILY','WEEKLY','MONTHLY') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'DAILY',
  `total_cases` int NULL DEFAULT 0,
  `executed_cases` int NULL DEFAULT 0,
  `passed_cases` int NULL DEFAULT 0,
  `failed_cases` int NULL DEFAULT 0,
  `broken_cases` int NULL DEFAULT 0,
  `skipped_cases` int NULL DEFAULT 0,
  `success_rate` decimal(5, 2) NULL DEFAULT 0.00,
  `total_duration` bigint NULL DEFAULT 0,
  `avg_duration` bigint NULL DEFAULT 0,
  `max_duration` bigint NULL DEFAULT 0,
  `min_duration` bigint NULL DEFAULT 0,
  `new_defects` int NULL DEFAULT 0,
  `fixed_defects` int NULL DEFAULT 0,
  `reopen_defects` int NULL DEFAULT 0,
  `environment` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '环境',
  `branch` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '代码分支',
  `version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '版本',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`trend_id`) USING BTREE,
  UNIQUE INDEX `uk_project_date_type`(`project_id` ASC, `trend_date` ASC, `trend_type` ASC) USING BTREE,
  INDEX `idx_project_date`(`project_id` ASC, `trend_date` ASC) USING BTREE,
  INDEX `idx_trend_type`(`trend_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '测试历史趋势表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of testhistorytrends
-- ----------------------------

-- ----------------------------
-- Table structure for testlogs
-- ----------------------------
DROP TABLE IF EXISTS `testlogs`;
CREATE TABLE `testlogs`  (
  `log_id` bigint NOT NULL AUTO_INCREMENT,
  `result_id` bigint NOT NULL COMMENT '关联TestCaseResults',
  `step_id` bigint NULL DEFAULT NULL COMMENT '关联TestStepResults',
  `log_level` enum('TRACE','DEBUG','INFO','WARN','ERROR','FATAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `log_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `log_timestamp` datetime NOT NULL,
  `logger_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '日志记录器名称',
  `thread_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '线程名称',
  `stack_trace` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '堆栈跟踪',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`log_id`) USING BTREE,
  INDEX `idx_result_id`(`result_id` ASC) USING BTREE,
  INDEX `idx_step_id`(`step_id` ASC) USING BTREE,
  INDEX `idx_log_level`(`log_level` ASC) USING BTREE,
  INDEX `idx_log_timestamp`(`log_timestamp` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 37 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '测试日志表' ROW_FORMAT = Dynamic;

