-- ----------------------------
-- Table structure for testrisks
-- ----------------------------
DROP TABLE IF EXISTS `testrisks`;
CREATE TABLE `testrisks`  (
  `risk_id` int NOT NULL AUTO_INCREMENT,
  `report_id` bigint NOT NULL,
  `risk_type` enum('DEFECT','COVERAGE','ENVIRONMENT','SCHEDULE','RESOURCE') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `risk_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `risk_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `probability` enum('LOW','MEDIUM','HIGH') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `impact` enum('LOW','MEDIUM','HIGH') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `risk_level` enum('LOW','MEDIUM','HIGH','CRITICAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `mitigation_plan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `mitigation_owner` int NULL DEFAULT NULL COMMENT '负责人',
  `mitigation_deadline` date NULL DEFAULT NULL,
  `status` enum('OPEN','IN_PROGRESS','RESOLVED','CLOSED') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'OPEN',
  `resolution_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `created_by` int NOT NULL,
  `updated_by` int NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`risk_id`) USING BTREE,
  INDEX `idx_report_id`(`report_id` ASC) USING BTREE,
  INDEX `idx_risk_type`(`risk_type` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '测试风险记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of testrisks
-- ----------------------------

-- ----------------------------
-- Table structure for teststepresults
-- ----------------------------
DROP TABLE IF EXISTS `teststepresults`;
CREATE TABLE `teststepresults`  (
  `step_id` bigint NOT NULL AUTO_INCREMENT,
  `result_id` bigint NOT NULL COMMENT '关联TestCaseResults',
  `step_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '步骤名称',
  `step_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '步骤描述',
  `step_status` enum('PASSED','FAILED','SKIPPED','PENDING') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `step_duration` bigint NULL DEFAULT 0 COMMENT '步骤耗时(毫秒)',
  `start_time` datetime NULL DEFAULT NULL COMMENT '步骤开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '步骤结束时间',
  `step_parameters` json NULL COMMENT '步骤参数',
  `step_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '步骤执行结果',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '步骤错误信息',
  `error_trace` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '错误堆栈',
  `screenshot_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '步骤截图',
  `log_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '步骤日志',
  `step_order` int NULL DEFAULT 0 COMMENT '步骤顺序',
  `parent_step_id` bigint NULL DEFAULT NULL COMMENT '父步骤ID，支持嵌套步骤',
  `step_level` int NULL DEFAULT 1 COMMENT '步骤层级',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`step_id`) USING BTREE,
  INDEX `idx_result_id`(`result_id` ASC) USING BTREE,
  INDEX `idx_step_status`(`step_status` ASC) USING BTREE,
  INDEX `idx_step_order`(`step_order` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '测试步骤执行详情表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of teststepresults
-- ----------------------------
